const fs = require('fs');
const path = require('path');
const Joi = require('joi');
const logger = require('../../../common/logger');

let cachedProblems;

const MAX_LIMIT = 50;

/**
 * Normalize tags filter into a lowercase array.
 * @param {string|Array<string>} rawTags
 * @returns {Array<string>}
 */
function normalizeTags(rawTags) {
  if (!rawTags && rawTags !== '') {
    return [];
  }
  if (typeof rawTags === 'string') {
    return rawTags.split(',').map((t) => t.trim().toLowerCase()).filter(Boolean);
  }
  if (Array.isArray(rawTags)) {
    return rawTags.map((t) => t.toLowerCase());
  }
  return [];
}

/**
 * Load problems from data file.
 * @returns {Array<Object>}
 */
function loadProblems() {
  if (!cachedProblems) {
    const filePath = path.join(__dirname, '../../data/problems.json');
    const content = fs.readFileSync(filePath, 'utf8');
    cachedProblems = JSON.parse(content);
  }
  return cachedProblems;
}

/**
 * Get problem by ID.
 * @param {string} problemId
 * @returns {Object|null}
 */
function getProblemById(problemId) {
  const problems = loadProblems();
  return problems.find((p) => p.id === problemId) || null;
}

/**
 * Aggregate component metadata for a problem.
 * @param {Object} problem
 * @returns {Object}
 */
function aggregateComponentMetadata(problem) {
  const components = problem.components || [];
  const languageCounts = {};
  const statusCounts = {};
  let maxPoints = 0;

  components.forEach((comp) => {
    if (comp.language) {
      languageCounts[comp.language] = (languageCounts[comp.language] || 0) + 1;
    }
    if (comp.status) {
      statusCounts[comp.status] = (statusCounts[comp.status] || 0) + 1;
    }
    if (typeof comp.points === 'number' && comp.points > maxPoints) {
      maxPoints = comp.points;
    }
  });

  return {
    languageCounts,
    statusCounts,
    maxPoints,
  };
}

